import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { derived, get, writable } from 'svelte/store';
import { createGame, createSudoku } from '../../../domain/index.js';
import { hints } from './hints';

const SUDOKU_SIZE = 9;

/**
 * 功能：创建一个全 0 的 9x9 空棋盘。
 * 上下文：此函数用于 gameSession 的默认初始状态，保证在真实题面加载前 store 结构稳定。
 *
 * @returns {number[][]}
 */
function createEmptyGrid() {
	return Array.from({ length: SUDOKU_SIZE }, () => Array(SUDOKU_SIZE).fill(0));
}

/**
 * 功能：基于题面创建一个前端会话对象。
 * 上下文：此函数位于 Svelte store 适配层，用于把领域对象包装成 UI 可消费的状态单元。
 * 逻辑：session 同时持有 puzzle 和 game：
 * puzzle 表示不可变题面，game 表示当前可变会话状态。
 * 这样 UI 仍然可以判断哪些格子是 givens，哪些格子允许编辑。
 *
 * @param {number[][]} puzzleInput
 * @returns {{ puzzle: ReturnType<typeof createSudoku>, game: ReturnType<typeof createGame> }}
 */
function createSessionFromPuzzle(puzzleInput) {
	const puzzle = createSudoku(puzzleInput);

	return {
		puzzle,
		game: createGame({ sudoku: puzzle }),
	};
}

/**
 * 功能：创建连接 UI 和领域层的会话 store。
 * 上下文：这是前端状态管理层的核心适配点，负责把 Game/Sudoku 的行为转成 Svelte store 可订阅的状态。
 * 逻辑：由于领域对象内部会发生可控的原地更新，store 必须通过 writable.update() 主动发出通知，
 * 否则即使内部状态变了，依赖它的 derived store 也不会重新计算。
 *
 * @returns {{
 *   subscribe: import('svelte/store').Writable<{ puzzle: ReturnType<typeof createSudoku>, game: ReturnType<typeof createGame> }>['subscribe'],
 *   loadPuzzle(puzzleInput: number[][]): void,
 *   loadSession(input: { puzzle: ReturnType<typeof createSudoku> | number[][], game?: ReturnType<typeof createGame> }): void,
 *   generate(difficulty: string): void,
 *   decodeSencode(sencode: string): void,
 *   guess(move: { row: number, col: number, value: number | null }): boolean,
 *   undo(): boolean,
 *   redo(): boolean,
 *   canUndo(): boolean,
 *   canRedo(): boolean,
 *   toJSON(): { sudoku: { grid: number[][] }, undoStack: Array<{ grid: number[][] }>, redoStack: Array<{ grid: number[][] }> },
 * }}
 */
function createGameSession() {
	const session = writable(createSessionFromPuzzle(createEmptyGrid()));

	/**
	 * 功能：执行一次会话更新并同步触发订阅者通知。
	 * 上下文：guess()、undo()、redo() 等方法都会通过此函数修改领域对象。
	 * 逻辑：虽然 session 对象本身的引用没有变化，但其内部的 Game/Sudoku 状态已经变化，
	 * 因此这里必须使用 writable.update() 强制让 derived store 重新计算。
	 *
	 * @param {(session: { puzzle: ReturnType<typeof createSudoku>, game: ReturnType<typeof createGame> }) => any} action
	 * @returns {any}
	 */
	function updateSession(action) {
		let result;

		session.update($session => {
			result = action($session);
			return $session;
		});

		return result;
	}

	return {
		subscribe: session.subscribe,

		loadPuzzle(puzzleInput) {
			session.set(createSessionFromPuzzle(puzzleInput));
		},

		loadSession({ puzzle, game }) {
			const normalizedPuzzle = puzzle && typeof puzzle.clone === 'function'
				? puzzle.clone()
				: createSudoku(puzzle);

			session.set({
				puzzle: normalizedPuzzle,
				game: game || createGame({ sudoku: normalizedPuzzle }),
			});
		},

		generate(difficulty) {
			this.loadPuzzle(generateSudoku(difficulty));
		},

		decodeSencode(sencode) {
			this.loadPuzzle(decodeSencode(sencode));
		},

		guess(move) {
			return updateSession($session => $session.game.guess(move));
		},

		undo() {
			return updateSession($session => $session.game.undo());
		},

		redo() {
			return updateSession($session => $session.game.redo());
		},

		canUndo() {
			return get(session).game.canUndo();
		},

		canRedo() {
			return get(session).game.canRedo();
		},

		toJSON() {
			return get(session).game.toJSON();
		},
	};
}

export const gameSession = createGameSession();

// 上下文：这里继续对原有 UI 暴露普通二维数组，
// 但真正的状态和历史仍然由领域层中的 Game / Sudoku 统一管理。
const puzzleGridStore = derived(gameSession, $session => $session.puzzle.getGrid());
const currentGridStore = derived(gameSession, $session => $session.game.getSudoku().getGrid());

/**
 * 功能：判断当前光标位置是否允许编辑。
 * 上下文：键盘输入和提示功能都会通过此函数过滤题目原始 givens。
 *
 * @param {{ x: number | null, y: number | null }} pos
 * @returns {boolean}
 */
function isEditableCell(pos) {
	if (!pos || pos.x === null || pos.y === null) {
		return false;
	}

	// 上下文：编辑权限现在优先由领域对象定义，而不再仅依赖 UI 自己判断 givens。
	// 逻辑：固定题面格属于数独业务规则，因此这里委托给 Game/Sudoku 领域对象判断。
	return !get(gameSession).game.isFixedCell(pos.y, pos.x);
}

export const grid = {
	subscribe: puzzleGridStore.subscribe,

	generate(difficulty) {
		gameSession.generate(difficulty);
	},

	decodeSencode(sencode) {
		gameSession.decodeSencode(sencode);
	},

	get(gridStore, x, y) {
		return gridStore[y][x];
	},

	getSencode(gridStore) {
		return encodeSudoku(gridStore);
	},
};

export const userGrid = {
	subscribe: currentGridStore.subscribe,

	set(pos, value) {
		if (!isEditableCell(pos)) {
			return false;
		}

		// 上下文：所有用户编辑都从这里进入领域层。
		// 逻辑：必须统一经过 Game.guess()，这样历史栈才会同步更新，undo/redo 才成立。
		return gameSession.guess({
			row: pos.y,
			col: pos.x,
			value,
		});
	},

	applyHint(pos) {
		if (!isEditableCell(pos)) {
			return false;
		}

		const currentGrid = get(currentGridStore);
		const solvedGrid = solveSudoku(currentGrid);
		const hintValue = solvedGrid[pos.y][pos.x];

		if (hintValue === currentGrid[pos.y][pos.x]) {
			return false;
		}

		hints.useHint();

		// 上下文：提示本质上也是一次对棋盘的写入。
		// 逻辑：这里仍然走 Game.guess()，这样 hint 会和普通输入一样进入 undo/redo 历史。
		return gameSession.guess({
			row: pos.y,
			col: pos.x,
			value: hintValue,
		});
	},
};

export const invalidCells = derived(
	gameSession,
	// 上下文：领域层返回结构化的 { row, col } 坐标，适配层再转换成旧 UI 使用的 "x,y" 字符串键。
	// 逻辑：这样既保留了领域接口的一致性，也避免一次性重写整个组件树。
	$session => $session.game.getSudoku().getInvalidCells().map(({ row, col }) => `${col},${row}`),
	[],
);

export const canUndo = derived(gameSession, $session => $session.game.canUndo(), false);
export const canRedo = derived(gameSession, $session => $session.game.canRedo(), false);
